import React from 'react'

function Profil() {
    return (
        <div className="profil mb5">
            <h2 className="h2">Profil</h2>
            <p> Rigoureuse, j’apporte une grande attention à la qualité de mon travail. Flexible, je m’adapte très vite à de nouveaux outils et langages informatiques que je découvre. Organisée, je veille à avoir une bonne gestion du temps et suis à l’aise avec le travail à distance.
            </p>

        </div>
    )
}

export default Profil
